from __future__ import annotations

import re
from dataclasses import dataclass, field
from email.utils import getaddresses
from typing import Any

from app.storage.stammdaten import StammdatenStore

_ENTITY_ID_RE = re.compile(r"\b(?:LIE|HAUS|EH|EIG|MIE|DL)-\d{2,5}\b", re.IGNORECASE)
_SOURCE_ID_RE = re.compile(r"\b(?:EMAIL|INV|LTR|TX)-[A-Z]*-?\d{3,6}\b", re.IGNORECASE)
_EMAIL_RE = re.compile(r"[\w.!#$%&'*+/=?^`{|}~-]+@[\w.-]+\.[A-Za-z]{2,}")
_IBAN_RE = re.compile(r"\b[A-Z]{2}\d{2}(?:[ ]?[A-Z0-9]){11,30}\b")


@dataclass(frozen=True)
class ResolvedEntity:
    id: str
    role: str
    source: str
    data: dict[str, Any] = field(default_factory=dict)


@dataclass(frozen=True)
class ResolutionResult:
    property_id: str
    entities: list[ResolvedEntity]
    mentioned_ids: list[str]
    source_ids: list[str]
    unresolved_ids: list[str]

    @property
    def entity_ids(self) -> list[str]:
        ids = [entity.id for entity in self.entities]
        ids.extend(self.mentioned_ids)
        return _dedupe(ids)


def resolve_context(
    *,
    normalized_text: str,
    stammdaten: StammdatenStore,
    property_id: str = "LIE-001",
) -> ResolutionResult:
    entities: list[ResolvedEntity] = []
    unresolved_ids: list[str] = []

    for email in _emails(normalized_text):
        row = stammdaten.find_entity_by_email(email)
        if row is not None:
            entities.extend(_entity_chain(row, source="email", stammdaten=stammdaten))

    for iban in _ibans(normalized_text):
        row = stammdaten.find_entity_by_iban(iban)
        if row is not None:
            entities.extend(_entity_chain(row, source="iban", stammdaten=stammdaten))

    mentioned_ids = []
    for entity_id in _entity_ids(normalized_text):
        row = stammdaten.find_entity_by_id(entity_id)
        if row is None:
            unresolved_ids.append(entity_id)
            continue
        mentioned_ids.append(entity_id)
        entities.extend(_entity_chain(row, source="mentioned_id", stammdaten=stammdaten))

    return ResolutionResult(
        property_id=property_id,
        entities=_dedupe_entities(entities),
        mentioned_ids=_dedupe(mentioned_ids),
        source_ids=_source_ids(normalized_text),
        unresolved_ids=_dedupe(unresolved_ids),
    )


def _emails(text: str) -> list[str]:
    raw_addresses = _EMAIL_RE.findall(text)
    parsed = [email for _, email in getaddresses(raw_addresses) if email]
    return _dedupe([email.lower() for email in parsed or raw_addresses])


def _ibans(text: str) -> list[str]:
    return _dedupe(match.group(0).replace(" ", "").upper() for match in _IBAN_RE.finditer(text))


def _entity_ids(text: str) -> list[str]:
    return _dedupe(match.group(0).upper() for match in _ENTITY_ID_RE.finditer(text))


def _source_ids(text: str) -> list[str]:
    return _dedupe(match.group(0).upper() for match in _SOURCE_ID_RE.finditer(text))


def _entity_chain(
    row: dict[str, Any],
    *,
    source: str,
    stammdaten: StammdatenStore,
) -> list[ResolvedEntity]:
    entities = [_entity_from_row(row, source)]
    for related_field in ("einheit_id", "eigentuemer_id", "haus_id"):
        related_id = row.get(related_field)
        if not isinstance(related_id, str) or not related_id:
            continue
        related = stammdaten.find_entity_by_id(related_id)
        if related is not None:
            entities.extend(_entity_chain(related, source=source, stammdaten=stammdaten))
    for unit_id in row.get("einheit_ids") or []:
        if not isinstance(unit_id, str):
            continue
        related = stammdaten.find_entity_by_id(unit_id)
        if related is not None:
            entities.extend(_entity_chain(related, source=source, stammdaten=stammdaten))
    return entities


def _entity_from_row(row: dict[str, Any], source: str) -> ResolvedEntity:
    entity_id = str(row["id"])
    role = str(row.get("role") or _role_from_id(entity_id))
    return ResolvedEntity(id=entity_id, role=role, source=source, data=row)


def _role_from_id(entity_id: str) -> str:
    prefix = entity_id.split("-", 1)[0].lower()
    return {
        "lie": "liegenschaft",
        "haus": "gebaeude",
        "eh": "einheit",
        "eig": "eigentuemer",
        "mie": "mieter",
        "dl": "dienstleister",
    }.get(prefix, "entity")


def _dedupe(values: list[str] | Any) -> list[str]:
    seen: set[str] = set()
    out: list[str] = []
    for value in values:
        text = str(value)
        if text in seen:
            continue
        seen.add(text)
        out.append(text)
    return out


def _dedupe_entities(entities: list[ResolvedEntity]) -> list[ResolvedEntity]:
    seen: set[str] = set()
    out: list[ResolvedEntity] = []
    for entity in entities:
        if entity.id in seen:
            continue
        seen.add(entity.id)
        out.append(entity)
    return out

from __future__ import annotations

import json
import re
import subprocess
from collections.abc import Mapping
from dataclasses import dataclass
from pathlib import Path
from typing import Any, cast

from app.services.patcher.atomic import atomic_write_text
from app.services.patcher.ops import (
    delete_bullet,
    delete_row,
    gc_footnotes,
    prepend_row,
    prune_ring,
    update_state,
    upsert_bullet,
    upsert_footnote,
    upsert_row,
)
from app.services.patcher.paths import property_file_path
from app.services.patcher.validate import (
    append_pending_review,
    parse_vocabulary,
    validate_keyed_values,
)
from app.services.reindex import reindex_files

_PROPERTY_ID_RE = re.compile(r"^LIE-\d{3}$")


@dataclass(frozen=True)
class PatchApplyResult:
    event_id: str
    applied_ops: int
    deferred_ops: int
    commit_sha: str | None
    idempotent: bool = False


def apply_patch_plan(
    plan: Mapping[str, Any],
    *,
    wiki_dir: Path,
    vocabulary_path: Path,
    wiki_chunks_db_path: Path | None = None,
) -> PatchApplyResult:
    event_id = str(plan["event_id"])
    property_id = str(plan["property_id"])
    if _PROPERTY_ID_RE.fullmatch(property_id) is None:
        raise ValueError("invalid property_id")
    property_root = wiki_dir / property_id
    feedback_path = property_root / "_hermes_feedback.jsonl"

    if _feedback_contains_event(feedback_path, event_id):
        return PatchApplyResult(
            event_id=event_id,
            applied_ops=0,
            deferred_ops=0,
            commit_sha=_head_sha(wiki_dir),
            idempotent=True,
        )

    ops = [op for op in plan.get("ops", []) if isinstance(op, dict)]
    vocabulary = parse_vocabulary(vocabulary_path)
    valid_ops, issues = validate_keyed_values(ops, vocabulary)
    append_pending_review(property_root, issues)

    touched: set[Path] = set()
    for op in valid_ops:
        touched.update(_apply_one(property_root, op))

    _append_feedback(feedback_path, plan, applied_ops=len(valid_ops), deferred_ops=len(issues))
    touched.add(feedback_path)
    if issues:
        touched.add(property_root / "_pending_review.md")

    commit_sha = _git_commit(
        wiki_dir,
        message=f"ingest({event_id}): {str(plan.get('summary', 'patch')).strip()}",
    )
    if wiki_chunks_db_path is not None:
        _reindex_touched_files(
            wiki_dir=wiki_dir,
            property_id=property_id,
            property_root=property_root,
            touched=touched,
            db_path=wiki_chunks_db_path,
        )
    return PatchApplyResult(
        event_id=event_id,
        applied_ops=len(valid_ops),
        deferred_ops=len(issues),
        commit_sha=commit_sha,
    )


def _apply_one(property_root: Path, op: Mapping[str, Any]) -> set[Path]:
    op_name = str(op["op"])
    if op_name == "update_state":
        path = property_file_path(property_root, str(op.get("file", "_state.json")))
        state = update_state(
            path,
            updates=_mapping_or_none(op.get("updates")),
            counters=_mapping_or_none(op.get("counters")),
        )
        atomic_write_text(path, json.dumps(state, indent=2, ensure_ascii=False) + "\n")
        return {path}

    file_path = property_file_path(property_root, str(op["file"]))
    content = file_path.read_text(encoding="utf-8")
    section = str(op.get("section", ""))

    if op_name == "upsert_bullet":
        content = upsert_bullet(
            content,
            section=section,
            key=str(op["key"]),
            text=str(op["text"]),
        )
    elif op_name == "delete_bullet":
        content = delete_bullet(content, section=section, key=str(op["key"]))
    elif op_name == "upsert_row":
        content = upsert_row(
            content,
            section=section,
            key=str(op["key"]),
            row=op["row"],
            header=_sequence_or_none(op.get("header")),
        )
    elif op_name == "delete_row":
        content = delete_row(content, section=section, key=str(op["key"]))
    elif op_name == "prepend_row":
        content = prepend_row(
            content,
            section=section,
            row=op["row"],
            header=_sequence_or_none(op.get("header")),
        )
    elif op_name == "prune_ring":
        content = prune_ring(content, section=section, max_rows=int(op["max_rows"]))
    elif op_name == "upsert_footnote":
        content = upsert_footnote(content, key=str(op["key"]), text=str(op["text"]))
    elif op_name == "gc_footnotes":
        content = gc_footnotes(content, ref_counts=_mapping_or_none(op.get("ref_counts")))
    else:
        raise ValueError(f"unknown patch op: {op_name}")

    atomic_write_text(file_path, content)
    return {file_path}


def _sequence_or_none(value: object) -> list[object] | None:
    if value is None:
        return None
    if isinstance(value, list):
        return cast("list[object]", value)
    if isinstance(value, tuple):
        return list(value)
    return [value]


def _mapping_or_none(value: object) -> dict[str, Any] | None:
    if value is None:
        return None
    if isinstance(value, dict):
        return cast("dict[str, Any]", value)
    raise TypeError(f"expected mapping, got {type(value).__name__}")


def _append_feedback(
    path: Path,
    plan: Mapping[str, Any],
    *,
    applied_ops: int,
    deferred_ops: int,
) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    existing = path.read_text(encoding="utf-8") if path.exists() else ""
    record = {
        "kind": "ingest",
        "event_id": plan["event_id"],
        "property_id": plan["property_id"],
        "summary": plan.get("summary", ""),
        "applied_ops": applied_ops,
        "deferred_ops": deferred_ops,
    }
    atomic_write_text(path, existing + json.dumps(record, ensure_ascii=False) + "\n")


def _feedback_contains_event(path: Path, event_id: str) -> bool:
    if not path.exists():
        return False
    for line in path.read_text(encoding="utf-8").splitlines():
        if not line.strip():
            continue
        try:
            record = json.loads(line)
        except json.JSONDecodeError:
            continue
        if record.get("event_id") == event_id:
            return True
    return False


def _git(args: list[str], cwd: Path, *, check: bool = True) -> subprocess.CompletedProcess[str]:
    return subprocess.run(  # noqa: S603
        ["git", *args],  # noqa: S607
        cwd=cwd,
        check=check,
        capture_output=True,
        text=True,
    )


def _git_commit(wiki_dir: Path, *, message: str) -> str | None:
    _git(["add", "-A"], cwd=wiki_dir)
    diff = _git(["diff", "--cached", "--quiet"], cwd=wiki_dir, check=False)
    if diff.returncode == 0:
        return _head_sha(wiki_dir)
    if diff.returncode != 1:
        raise subprocess.CalledProcessError(diff.returncode, diff.args, diff.stdout, diff.stderr)
    _git(["commit", "-m", message], cwd=wiki_dir)
    return _head_sha(wiki_dir)


def _head_sha(wiki_dir: Path) -> str | None:
    result = _git(["rev-parse", "HEAD"], cwd=wiki_dir, check=False)
    if result.returncode != 0:
        return None
    return result.stdout.strip()


def _reindex_touched_files(
    *,
    wiki_dir: Path,
    property_id: str,
    property_root: Path,
    touched: set[Path],
    db_path: Path,
) -> None:
    files = []
    for path in touched:
        if path.suffix != ".md":
            continue
        try:
            files.append(path.relative_to(property_root))
        except ValueError:
            continue
    if files:
        reindex_files(wiki_dir=wiki_dir, property_id=property_id, files=files, db_path=db_path)

from __future__ import annotations

import json
import re
from collections.abc import Mapping, Sequence
from datetime import UTC, datetime
from pathlib import Path
from typing import Any

HUMAN_NOTES_HEADING = "# Human Notes"


class PatchOperationError(ValueError):
    """Raised when a patch operation would touch unmanaged markdown."""


def _human_notes_start(content: str) -> int:
    marker = f"\n{HUMAN_NOTES_HEADING}"
    idx = content.find(marker)
    if idx == -1:
        if content.startswith(HUMAN_NOTES_HEADING):
            return 0
        raise PatchOperationError("missing # Human Notes boundary")
    return idx + 1


def _managed_content_end(content: str) -> int:
    return _human_notes_start(content)


def _section_bounds(content: str, section: str) -> tuple[int, int]:
    managed_end = _managed_content_end(content)
    managed = content[:managed_end]
    heading_re = re.compile(rf"^## {re.escape(section)}\s*$", re.MULTILINE)
    match = heading_re.search(managed)
    if match is None:
        raise PatchOperationError(f"section not found before # Human Notes: {section}")

    next_heading = re.search(r"^## .*$", managed[match.end() :], re.MULTILINE)
    end = managed_end if next_heading is None else match.end() + next_heading.start()
    if end > managed_end:
        raise PatchOperationError("operation would cross # Human Notes boundary")
    return match.end(), end


def _section_lines(content: str, section: str) -> tuple[int, int, list[str]]:
    start, end = _section_bounds(content, section)
    return start, end, content[start:end].splitlines(keepends=True)


def _replace_section_lines(content: str, section: str, lines: Sequence[str]) -> str:
    start, end = _section_bounds(content, section)
    body = "".join(lines)
    if body and not body.endswith("\n"):
        body += "\n"
    return f"{content[:start]}{body}{content[end:]}"


def _ensure_section_spacing(lines: list[str]) -> list[str]:
    if not lines:
        return ["\n"]
    if lines[0].strip():
        lines.insert(0, "\n")
    if lines[-1].strip():
        lines.append("\n")
    return lines


def _strip_empty_state(lines: list[str]) -> list[str]:
    return [line for line in lines if not line.lstrip().startswith("_Keine ")]


def _keyed_bullet_re(key: str) -> re.Pattern[str]:
    return re.compile(rf"^\s*-\s+.*\*\*{re.escape(key)}:\*\*")


def _normalize_bullet(key: str, text: str) -> str:
    line = text.strip()
    if not line.startswith("- "):
        line = f"- **{key}:** {line}"
    elif f"**{key}:**" not in line:
        line = f"- **{key}:** {line[2:].strip()}"
    return f"{line}\n"


def upsert_bullet(content: str, *, section: str, key: str, text: str) -> str:
    _, _, lines = _section_lines(content, section)
    lines = _strip_empty_state(lines)
    new_line = _normalize_bullet(key, text)
    keyed = _keyed_bullet_re(key)

    for idx, line in enumerate(lines):
        if keyed.match(line):
            lines[idx] = new_line
            return _replace_section_lines(content, section, _ensure_section_spacing(lines))

    insert_at = len(lines)
    while insert_at > 0 and not lines[insert_at - 1].strip():
        insert_at -= 1
    lines.insert(insert_at, new_line)
    return _replace_section_lines(content, section, _ensure_section_spacing(lines))


def delete_bullet(content: str, *, section: str, key: str) -> str:
    _, _, lines = _section_lines(content, section)
    keyed = _keyed_bullet_re(key)
    lines = [line for line in lines if not keyed.match(line)]
    return _replace_section_lines(content, section, _ensure_section_spacing(lines))


def _normalize_cells(row: str | Sequence[object]) -> list[str]:
    if isinstance(row, str):
        stripped = row.strip().strip("|")
        return [cell.strip() for cell in stripped.split("|")]
    return [str(cell).strip() for cell in row]


def _render_row(cells: str | Sequence[object]) -> str:
    return "| " + " | ".join(_normalize_cells(cells)) + " |\n"


def _is_table_row(line: str) -> bool:
    return line.lstrip().startswith("|") and line.rstrip().endswith("|")


def _is_separator(line: str) -> bool:
    return bool(re.match(r"^\s*\|?\s*:?-{3,}:?\s*(\|\s*:?-{3,}:?\s*)+\|?\s*$", line))


def _table_bounds(lines: Sequence[str]) -> tuple[int, int] | None:
    start = None
    for idx, line in enumerate(lines):
        if _is_table_row(line):
            start = idx
            break
    if start is None:
        return None
    end = start
    while end < len(lines) and (_is_table_row(lines[end]) or not lines[end].strip()):
        if not _is_table_row(lines[end]) and end > start:
            break
        end += 1
    return start, end


def _row_key(line: str) -> str | None:
    if not _is_table_row(line) or _is_separator(line):
        return None
    cells = _normalize_cells(line)
    if not cells:
        return None
    return cells[0]


def _table_insert_index(lines: Sequence[str], start: int, end: int) -> int:
    if start + 1 < end and _is_separator(lines[start + 1]):
        return start + 2
    return start + 1


def upsert_row(
    content: str,
    *,
    section: str,
    key: str,
    row: str | Sequence[object],
    header: Sequence[object] | None = None,
) -> str:
    _, _, lines = _section_lines(content, section)
    lines = _strip_empty_state(lines)
    rendered = _render_row(row)
    bounds = _table_bounds(lines)

    if bounds is None:
        table = []
        if header is not None:
            header_cells = _normalize_cells(header)
            table.append(_render_row(header_cells))
            table.append(_render_row(["---"] * len(header_cells)))
        table.append(rendered)
        insert_at = len(lines)
        while insert_at > 0 and not lines[insert_at - 1].strip():
            insert_at -= 1
        lines[insert_at:insert_at] = table
        return _replace_section_lines(content, section, _ensure_section_spacing(lines))

    start, end = bounds
    for idx in range(start, end):
        if _row_key(lines[idx]) == key:
            lines[idx] = rendered
            return _replace_section_lines(content, section, _ensure_section_spacing(lines))

    lines.insert(end, rendered)
    return _replace_section_lines(content, section, _ensure_section_spacing(lines))


def delete_row(content: str, *, section: str, key: str) -> str:
    _, _, lines = _section_lines(content, section)
    bounds = _table_bounds(lines)
    if bounds is None:
        return content
    start, end = bounds
    kept = [
        line for idx, line in enumerate(lines) if idx < start or idx >= end or _row_key(line) != key
    ]
    return _replace_section_lines(content, section, _ensure_section_spacing(kept))


def prepend_row(
    content: str,
    *,
    section: str,
    row: str | Sequence[object],
    header: Sequence[object] | None = None,
) -> str:
    _, _, lines = _section_lines(content, section)
    lines = _strip_empty_state(lines)
    rendered = _render_row(row)
    bounds = _table_bounds(lines)

    if bounds is None:
        table = []
        if header is not None:
            header_cells = _normalize_cells(header)
            table.append(_render_row(header_cells))
            table.append(_render_row(["---"] * len(header_cells)))
        table.append(rendered)
        insert_at = len(lines)
        while insert_at > 0 and not lines[insert_at - 1].strip():
            insert_at -= 1
        lines[insert_at:insert_at] = table
        return _replace_section_lines(content, section, _ensure_section_spacing(lines))

    start, end = bounds
    lines.insert(_table_insert_index(lines, start, end), rendered)
    return _replace_section_lines(content, section, _ensure_section_spacing(lines))


def prune_ring(content: str, *, section: str, max_rows: int) -> str:
    if max_rows < 0:
        raise PatchOperationError("max_rows must be non-negative")
    _, _, lines = _section_lines(content, section)
    bounds = _table_bounds(lines)
    if bounds is None:
        bullet_indexes = [idx for idx, line in enumerate(lines) if line.lstrip().startswith("- ")]
        for idx in reversed(bullet_indexes[max_rows:]):
            del lines[idx]
        return _replace_section_lines(content, section, _ensure_section_spacing(lines))

    start, end = bounds
    first_data = _table_insert_index(lines, start, end)
    data_indexes = [
        idx
        for idx in range(first_data, end)
        if _is_table_row(lines[idx]) and not _is_separator(lines[idx])
    ]
    for idx in reversed(data_indexes[max_rows:]):
        del lines[idx]
    return _replace_section_lines(content, section, _ensure_section_spacing(lines))


def upsert_footnote(content: str, *, key: str, text: str) -> str:
    section = "Provenance"
    _, _, lines = _section_lines(content, section)
    new_line = f"[^{key}]: {text.strip()}\n"
    pattern = re.compile(rf"^\[\^{re.escape(key)}\]:")
    for idx, line in enumerate(lines):
        if pattern.match(line):
            lines[idx] = new_line
            return _replace_section_lines(content, section, _ensure_section_spacing(lines))
    insert_at = len(lines)
    while insert_at > 0 and not lines[insert_at - 1].strip():
        insert_at -= 1
    lines.insert(insert_at, new_line)
    return _replace_section_lines(content, section, _ensure_section_spacing(lines))


def gc_footnotes(content: str, *, ref_counts: Mapping[str, int] | None = None) -> str:
    _, _, lines = _section_lines(content, "Provenance")
    if ref_counts is None:
        start, _ = _section_bounds(content, "Provenance")
        before_provenance = content[:start]
        refs = set(re.findall(r"\[\^([^\]]+)\]", before_provenance))
    else:
        refs = {key for key, count in ref_counts.items() if count > 0}

    kept = []
    footnote_re = re.compile(r"^\[\^([^\]]+)\]:")
    for line in lines:
        match = footnote_re.match(line)
        if match is not None and match.group(1) not in refs:
            continue
        kept.append(line)
    return _replace_section_lines(content, "Provenance", _ensure_section_spacing(kept))


def update_state(
    state_path: Path,
    *,
    updates: Mapping[str, Any] | None = None,
    counters: Mapping[str, int] | None = None,
) -> dict[str, Any]:
    state = json.loads(state_path.read_text(encoding="utf-8"))
    for key, value in (updates or {}).items():
        state[key] = value
    if counters:
        counts = state.setdefault("counts", {})
        for key, delta in counters.items():
            counts[key] = int(counts.get(key, 0)) + delta
    state["last_patched"] = datetime.now(UTC).isoformat()
    return state

from __future__ import annotations

import re
from dataclasses import dataclass
from datetime import date
from decimal import Decimal, InvalidOperation
from pathlib import Path
from typing import Any

from app.schemas.patch_plan import PatchPlan
from app.services.patcher.pending_review import append_entries as _append_pending_entries

_DATE_RE = re.compile(r"\b(20\d{2}-\d{2}-\d{2})\b")
_MONEY_RE = re.compile(r"(?:€\s*)?(-?\d+(?:[.\s]\d{3})*(?:,\d{2}|\.\d{2}))\s*(?:€|EUR)?")
_BULLET_STATUS_RE = re.compile(r"^\s*-\s*(?P<status>[🔴🟡🟢])")


@dataclass(frozen=True)
class ConflictIssue:
    file: str
    section: str
    key: str
    reason: str
    existing: str
    incoming: str


def scan_patch_plan_conflicts(
    plan: PatchPlan,
    *,
    wiki_dir: Path,
    date_drift_days: int = 3,
    amount_delta_ratio: Decimal = Decimal("0.10"),
) -> tuple[PatchPlan, list[ConflictIssue]]:
    kept_ops: list[dict[str, Any]] = []
    issues: list[ConflictIssue] = []
    property_root = wiki_dir / plan.property_id

    for op in plan.ops:
        op_data = op.model_dump(exclude_none=True)
        issue = _conflict_for_op(
            op_data,
            property_root=property_root,
            date_drift_days=date_drift_days,
            amount_delta_ratio=amount_delta_ratio,
        )
        if issue is None:
            kept_ops.append(op_data)
        else:
            issues.append(issue)

    if issues:
        append_conflicts(property_root, issues)

    data = plan.model_dump()
    data["ops"] = kept_ops
    return PatchPlan.model_validate(data), issues


def append_conflicts(property_root: Path, issues: list[ConflictIssue]) -> None:
    if not issues:
        return
    entries = [
        "\n".join(
            [
                "",
                f"### conflict: {issue.key}",
                f"- file: `{issue.file}`",
                f"- section: `{issue.section}`",
                f"- reason: {issue.reason}",
                f"- existing: `{issue.existing}`",
                f"- incoming: `{issue.incoming}`",
                "",
            ]
        )
        for issue in issues
    ]
    _append_pending_entries(property_root / "_pending_review.md", entries)


def _conflict_for_op(
    op: dict[str, Any],
    *,
    property_root: Path,
    date_drift_days: int,
    amount_delta_ratio: Decimal,
) -> ConflictIssue | None:
    if op.get("op") not in {"upsert_bullet", "upsert_row"}:
        return None
    file = str(op.get("file", ""))
    section = str(op.get("section", ""))
    key = str(op.get("key", ""))
    if not file or not section or not key:
        return None
    path = property_root / file
    if not path.is_file():
        return None
    existing = _existing_keyed_line(path.read_text(encoding="utf-8"), section=section, key=key)
    if existing is None:
        return None
    incoming = _incoming_line(op)
    reason = _conflict_reason(
        existing,
        incoming,
        date_drift_days=date_drift_days,
        amount_delta_ratio=amount_delta_ratio,
    )
    if reason is None:
        return None
    return ConflictIssue(
        file=file,
        section=section,
        key=key,
        reason=reason,
        existing=existing,
        incoming=incoming,
    )


def _existing_keyed_line(content: str, *, section: str, key: str) -> str | None:
    body = _section_body(content, section)
    if body is None:
        return None
    bullet_key = re.compile(rf"\*\*{re.escape(key)}:\*\*")
    for line in body.splitlines():
        if line.lstrip().startswith("- ") and bullet_key.search(line):
            return line.strip()
        if line.lstrip().startswith("|") and _row_key(line) == key:
            return line.strip()
    return None


def _section_body(content: str, section: str) -> str | None:
    managed = content.split("\n# Human Notes", 1)[0]
    match = re.search(rf"^## {re.escape(section)}\s*$", managed, flags=re.MULTILINE)
    if match is None:
        return None
    next_match = re.search(r"^## .*$", managed[match.end() :], flags=re.MULTILINE)
    end = len(managed) if next_match is None else match.end() + next_match.start()
    return managed[match.end() : end]


def _row_key(line: str) -> str | None:
    cells = [cell.strip() for cell in line.strip().strip("|").split("|")]
    if not cells or set(cells[0]) <= {"-"}:
        return None
    return cells[0]


def _incoming_line(op: dict[str, Any]) -> str:
    if op.get("op") == "upsert_bullet":
        text = str(op.get("text") or op.get("content") or "")
        if text.lstrip().startswith("- "):
            return text.strip()
        key = str(op.get("key", ""))
        return f"- **{key}:** {text.strip()}"
    row = op.get("row") or op.get("content") or ""
    if isinstance(row, list):
        return "| " + " | ".join(str(cell).strip() for cell in row) + " |"
    return str(row).strip()


def _conflict_reason(
    existing: str,
    incoming: str,
    *,
    date_drift_days: int,
    amount_delta_ratio: Decimal,
) -> str | None:
    old_status = _status(existing)
    new_status = _status(incoming)
    if old_status == "🔴" and new_status == "🟢":
        return "status flip requires human approval"

    old_date = _first_date(existing)
    new_date = _first_date(incoming)
    if (
        old_date is not None
        and new_date is not None
        and abs((new_date - old_date).days) > date_drift_days
    ):
        return f"date drift exceeds {date_drift_days} days"

    old_amount = _first_amount(existing)
    new_amount = _first_amount(incoming)
    if old_amount is not None and new_amount is not None and old_amount != 0:
        delta = abs(new_amount - old_amount) / abs(old_amount)
        if delta > amount_delta_ratio:
            return f"amount delta exceeds {amount_delta_ratio:.0%}"
    return None


def _status(line: str) -> str | None:
    match = _BULLET_STATUS_RE.match(line)
    return match.group("status") if match is not None else None


def _first_date(line: str) -> date | None:
    match = _DATE_RE.search(line)
    if match is None:
        return None
    try:
        return date.fromisoformat(match.group(1))
    except ValueError:
        return None


def _first_amount(line: str) -> Decimal | None:
    for match in _MONEY_RE.finditer(line):
        raw = match.group(1).replace(" ", "")
        if raw.count(",") == 1:
            raw = raw.replace(".", "").replace(",", ".")
        try:
            return Decimal(raw)
        except InvalidOperation:
            continue
    return None

