1	import { useEffect, useMemo, useRef, useState } from "react";
2	import { X } from "lucide-react";
3	import type { PanelImperativeHandle } from "react-resizable-panels";
4	import { Group, Panel, Separator } from "react-resizable-panels";
5	import { TopBar } from "./components/TopBar";
6	import { Tree } from "./components/Tree";
7	import { Viewer } from "./components/Viewer";
8	import { Query } from "./components/Query";
9	import { Palette } from "./components/Palette";
10	import { fetchFile, fetchProperties, fetchTree } from "./api";
11	import type { TreeNode } from "./api";
12	import { flattenTree } from "./lib/markdown";
13	
14	export default function App() {
15	  const [properties, setProperties] = useState<string[]>([]);
16	  const [lie, setLie] = useState<string>("");
17	  const [tree, setTree] = useState<TreeNode | null>(null);
18	  const [path, setPath] = useState<string | null>(null);
19	  const [content, setContent] = useState<string>("");
20	  const [loading, setLoading] = useState(false);
21	  const [error, setError] = useState<string | null>(null);
22	  const [paletteOpen, setPaletteOpen] = useState(false);
23	  const [askCollapsed, setAskCollapsed] = useState(false);
24	  const [treeCollapsed, setTreeCollapsed] = useState(false);
25	  const [isMobile, setIsMobile] = useState(false);
26	  const [mobileTreeOpen, setMobileTreeOpen] = useState(false);
27	  const [mobileAskOpen, setMobileAskOpen] = useState(false);
28	  const askPanelRef = useRef<PanelImperativeHandle | null>(null);
29	  const treePanelRef = useRef<PanelImperativeHandle | null>(null);
30	
31	  useEffect(() => {
32	    const mq = window.matchMedia("(max-width: 768px)");
33	    const update = () => setIsMobile(mq.matches);
34	    update();
35	    mq.addEventListener("change", update);
36	    return () => mq.removeEventListener("change", update);
37	  }, []);
38	
39	  useEffect(() => {
40	    fetchProperties()
41	      .then((ps) => {
42	        setProperties(ps);
43	        if (ps.length > 0) setLie(ps[0]);
44	      })
45	      .catch((e) => setError(String(e)));
46	  }, []);
47	
48	  useEffect(() => {
49	    if (!lie) return;
50	    setTree(null);
51	    setPath(null);
52	    setContent("");
53	    fetchTree(lie)
54	      .then((t) => {
55	        setTree(t);
56	        setPath(`${lie}/index.md`);
57	      })
58	      .catch((e) => setError(String(e)));
59	  }, [lie]);
60	
61	  useEffect(() => {
62	    if (!path) return;
63	    setLoading(true);
64	    setError(null);
65	    fetchFile(path)
66	      .then((c) => setContent(c))
67	      .catch((e) => {
68	        setError(String(e));
69	        setContent("");
70	      })
71	      .finally(() => setLoading(false));
72	  }, [path]);
73	
74	  const flatFiles = useMemo(() => (tree ? flattenTree(tree) : []), [tree]);
75	
76	  function toggleAsk() {
77	    if (isMobile) {
78	      setMobileAskOpen((v) => !v);
79	      return;
80	    }
81	    const panel = askPanelRef.current;
82	    if (!panel) return;
83	    if (panel.isCollapsed()) panel.expand();
84	    else panel.collapse();
85	  }
86	
87	  function toggleTree() {
88	    if (isMobile) {
89	      setMobileTreeOpen((v) => !v);
90	      return;
91	    }
92	    const panel = treePanelRef.current;
93	    if (!panel) return;
94	    if (panel.isCollapsed()) panel.expand();
95	    else panel.collapse();
96	  }
97	
98	  function selectPath(p: string) {
99	    setPath(p);
100	    if (isMobile) {
101	      setMobileTreeOpen(false);
102	      setMobileAskOpen(false);
103	    }
104	  }
105	
106	  const treeButtonActive = isMobile ? mobileTreeOpen : !treeCollapsed;
107	  const askButtonActive = isMobile ? mobileAskOpen : !askCollapsed;
108	
109	  const treeSidebar = (
110	    <aside className="flex h-full flex-col border-r border-[var(--color-border)] bg-[var(--color-bg)]/40">
111	      <div className="flex flex-col gap-2 border-b border-[var(--color-border)] px-3 py-2">
112	        <div className="flex items-center justify-between">
113	          <span className="font-mono text-[10.5px] uppercase tracking-[0.2em] text-[var(--color-fg-dim)]">
114	            Property
115	          </span>
116	          {tree && (
117	            <span className="font-mono text-[10.5px] text-[var(--color-fg-dim)]">
118	              {flatFiles.length} files
119	            </span>
120	          )}
121	        </div>
122	        <div className="relative">
123	          <select
124	            value={lie}
125	            onChange={(e) => setLie(e.target.value)}
126	            disabled={properties.length === 0}
127	            className="h-7 w-full cursor-pointer appearance-none rounded-md border border-[var(--color-border-2)] bg-[var(--color-surface)] px-2.5 pr-7 font-mono text-[12px] font-medium text-[var(--color-fg)] outline-none transition-colors hover:border-[var(--color-accent-dim)] focus:border-[var(--color-accent)]"
128	          >
129	            {properties.map((p) => (
130	              <option key={p} value={p}>
131	                {p}
132	              </option>
133	            ))}
134	          </select>
135	          <span className="pointer-events-none absolute right-2 top-1/2 -translate-y-1/2 text-[var(--color-fg-muted)]">
136	            <svg width="8" height="6" viewBox="0 0 8 6" fill="none">
137	              <path
138	                d="M1 1.5L4 4.5L7 1.5"
139	                stroke="currentColor"
140	                strokeWidth="1.4"
141	                strokeLinecap="round"
142	              />
143	            </svg>
144	          </span>
145	        </div>
146	      </div>
147	      <div className="flex-1 overflow-auto px-1.5 py-2">
148	        {tree ? (
149	          <Tree node={tree} selectedPath={path} onSelect={selectPath} isRoot />
150	        ) : (
151	          <TreeSkeleton />
152	        )}
153	      </div>
154	    </aside>
155	  );
156	
157	  return (
158	    <div className="flex h-screen flex-col overflow-hidden">
159	      <TopBar
160	        onOpenPalette={() => setPaletteOpen(true)}
161	        askActive={askButtonActive}
162	        onToggleAsk={toggleAsk}
163	        treeActive={treeButtonActive}
164	        onToggleTree={toggleTree}
165	      />
166	
167	      <div className="min-h-0 flex-1">
168	        {isMobile ? (
169	          <main className="flex h-full min-w-0 flex-col">
170	            <div className="min-h-0 flex-1">
171	              <Viewer
172	                path={path}
173	                content={content}
174	                loading={loading}
175	                error={error}
176	              />
177	            </div>
178	          </main>
179	        ) : (
180	          <Group orientation="horizontal" className="h-full">
181	            <Panel
182	              panelRef={treePanelRef}
183	              defaultSize="20%"
184	              minSize="14%"
185	              maxSize="32%"
186	              collapsible
187	              collapsedSize="0%"
188	              onResize={(size) => setTreeCollapsed(size.asPercentage < 1)}
189	              className="tree-panel overflow-hidden"
190	            >
191	              {!treeCollapsed && treeSidebar}
192	            </Panel>
193	
194	            <Separator />
195	
196	            <Panel defaultSize="56%" minSize="32%" className="overflow-hidden">
197	              <main className="flex h-full min-w-0 flex-col">
198	                <div className="min-h-0 flex-1">
199	                  <Viewer
200	                    path={path}
201	                    content={content}
202	                    loading={loading}
203	                    error={error}
204	                  />
205	                </div>
206	              </main>
207	            </Panel>
208	
209	            <Separator />
210	
211	            <Panel
212	              panelRef={askPanelRef}
213	              defaultSize="24%"
214	              minSize="18%"
215	              maxSize="42%"
216	              collapsible
217	              collapsedSize="0%"
218	              onResize={(size) => setAskCollapsed(size.asPercentage < 1)}
219	              className="ask-panel overflow-hidden"
220	            >
221	              {!askCollapsed && <Query lie={lie} onResolved={selectPath} />}
222	            </Panel>
223	          </Group>
224	        )}
225	      </div>
226	
227	      {isMobile && (
228	        <div
229	          className={`fixed inset-0 z-50 flex transform flex-col bg-[var(--color-bg)] transition-transform duration-200 ${
230	            mobileTreeOpen ? "translate-x-0" : "-translate-x-full"
231	          }`}
232	        >
233	          <MobileDrawerHeader
234	            label="Tree"
235	            onClose={() => setMobileTreeOpen(false)}
236	          />
237	          <div className="min-h-0 flex-1">{treeSidebar}</div>
238	        </div>
239	      )}
240	
241	      {isMobile && (
242	        <div
243	          className={`fixed inset-0 z-50 flex transform flex-col bg-[var(--color-bg)] transition-transform duration-200 ${
244	            mobileAskOpen ? "translate-x-0" : "translate-x-full"
245	          }`}
246	        >
247	          <MobileDrawerHeader
248	            label="Ask"
249	            onClose={() => setMobileAskOpen(false)}
250	          />
251	          <div className="min-h-0 flex-1">
252	            <Query lie={lie} onResolved={selectPath} />
253	          </div>
254	        </div>
255	      )}
256	
257	      <Palette
258	        open={paletteOpen}
259	        onOpenChange={setPaletteOpen}
260	        files={flatFiles}
261	        onSelect={selectPath}
262	      />
263	    </div>
264	  );
265	}
266	
267	function MobileDrawerHeader({
268	  label,
269	  onClose,
270	}: {
271	  label: string;
272	  onClose: () => void;
273	}) {
274	  return (
275	    <div className="flex h-12 shrink-0 items-center justify-between border-b border-[var(--color-border)] bg-[var(--color-surface)]/60 px-3">
276	      <span className="font-mono text-[10.5px] uppercase tracking-[0.2em] text-[var(--color-fg-muted)]">
277	        {label}
278	      </span>
279	      <button
280	        aria-label={`Close ${label} panel`}
281	        onClick={onClose}
282	        className="grid h-8 w-8 place-items-center rounded-md border border-[var(--color-border-2)] bg-[var(--color-surface)] text-[var(--color-fg-muted)] transition-colors hover:border-[var(--color-accent-dim)] hover:text-[var(--color-fg)]"
283	      >
284	        <X className="h-4 w-4" />
285	      </button>
286	    </div>
287	  );
288	}
